options.customCss:
:root {
  /* =========================
     BRAND COLORS (Big Mamma Style)
  ========================== */

  --chat--color-primary: #5a1e1e;             /* deep wine red */
  --chat--color-primary-shade-50: #4a1818;
  --chat--color-primary-shade-100: #3a1212;

  --chat--color-secondary: #7a2e2e;           /* softer burgundy */
  --chat--color-secondary-shade-50: #622525;

  --chat--color-white: #ffffff;

  --chat--color-light: #f4efe7;               /* warm cream background */
  --chat--color-light-shade-50: #e8dfd4;
  --chat--color-light-shade-100: #d8cec1;

  --chat--color-medium: #c9bfb3;
  --chat--color-dark: #2c1a14;                /* espresso brown */
  --chat--color-disabled: #d8cec1;
  --chat--color-typing: #5c4a42;

  /* =========================
     LAYOUT
  ========================== */

  --chat--spacing: 1.2rem;
  --chat--border-radius: 14px;
  --chat--transition-duration: 0.2s;

  --chat--font-family: "Playfair Display", Georgia, serif;

  /* =========================
     WINDOW SIZE (More Premium)
  ========================== */

  --chat--window--width: 420px;
  --chat--window--height: 680px;
  --chat--window--bottom: 2rem;
  --chat--window--right: 2rem;
  --chat--window--z-index: 9999;
  --chat--window--border: 1px solid #e8dfd4;
  --chat--window--border-radius: 18px;
  --chat--window--margin-bottom: var(--chat--spacing);

  /* =========================
     HEADER
  ========================== */

  --chat--header--padding: 1.4rem;
  --chat--header--background: var(--chat--color-dark);
  --chat--header--color: #f4efe7;

  --chat--heading--font-size: 1.6rem;
  --chat--subtitle--font-size: 0.95rem;
  --chat--subtitle--line-height: 1.6;

  /* =========================
     MESSAGES
  ========================== */

  --chat--message--font-size: 0.95rem;
  --chat--message--padding: 1rem 1.2rem;
  --chat--message--border-radius: 18px;
  --chat--message-line-height: 1.6;
  --chat--message--margin-bottom: 1rem;

  /* Bot message (cream card look) */
  --chat--message--bot--background: #ffffff;
  --chat--message--bot--color: var(--chat--color-dark);
  --chat--message--bot--border: 1px solid #e8dfd4;

  /* User message (wine bubble) */
  --chat--message--user--background: var(--chat--color-primary);
  --chat--message--user--color: #ffffff;
  --chat--message--user--border: none;

  --chat--messages-list--padding: 1.5rem;

  /* =========================
     TOGGLE BUTTON (Floating)
  ========================== */

  --chat--toggle--size: 70px;
  --chat--toggle--border-radius: 50%;
  --chat--toggle--background: var(--chat--color-primary);
  --chat--toggle--hover--background: var(--chat--color-primary-shade-50);
  --chat--toggle--active--background: var(--chat--color-primary-shade-100);
  --chat--toggle--color: #ffffff;

  /* =========================
     INPUT AREA
  ========================== */

  --chat--textarea--height: 60px;
  --chat--textarea--max-height: 20rem;

  --chat--input--padding: 1rem;
  --chat--input--background: #ffffff;
  --chat--input--border: none;
  --chat--input--border-radius: 0;
  --chat--input--text-color: var(--chat--color-dark);

  /* =========================
     BUTTONS
  ========================== */

  --chat--button--background: var(--chat--color-primary);
  --chat--button--color: #ffffff;
  --chat--button--border-radius: 20px;

  --chat--button--hover--background: var(--chat--color-primary-shade-50);

  /* =========================
     BODY + FOOTER
  ========================== */

  --chat--body--background: var(--chat--color-light);
  --chat--footer--background: #f4efe7;
  --chat--footer--color: var(--chat--color-dark);
}


/* Wider chat bubbles for better readability */
.chat-message {
  max-width: 75%;
}
